  --component-input-border-hover:    var(--semantic-color-border-strong,   /* ⚠️ TOKEN_MANQUANT: semantic.color.border.strong   — Figma: {color.border.strong}   */ #6b7280);
  --component-input-border-focus:    var(--semantic-color-border-focus,    /* ⚠️ TOKEN_MANQUANT: semantic.color.border.focus    — Figma: {color.border.focus}    */ #3b82f6);
  --component-input-border-error:    var(--semantic-color-danger-500,      /* ⚠️ TOKEN_MANQUANT: semantic.color.danger.500      — Figma: {color.danger.500}      */ #ef4444);
  --component-input-border-disabled: var(--semantic-color-border-disabled, /* ⚠️ TOKEN_MANQUANT: semantic.color.border.disabled — Figma: {color.border.disabled} */ #e5e7eb);

  /* Shape */
  --component-input-radius:       var(--semantic-radius-md,          /* ⚠️ TOKEN_MANQUANT: semantic.radius.md          — Figma: {radius.md}          */ 6px);
  --component-input-border-width: var(--semantic-border-width-default,/* ⚠️ TOKEN_MANQUANT: semantic.borderWidth.default — Figma: {borderWidth.default} */ 1px);

  /* Focus ring (WCAG AA) */
  --component-input-focus-ring-width:  2px;
  --component-input-focus-ring-offset: 2px;
  --component-input-focus-ring-color:  var(--semantic-color-border-emphasis, var(--component-input-border-focus));

  /* Transition */
  --component-input-transition: border-color 150ms ease, box-shadow 150ms ease, background-color 150ms ease;
}


.input-field {
  display: flex;
  flex-direction: column;
  gap: var(--semantic-spacing-xs, 4px);
  width: 100%;
}


.input-field__label {
  font-family: var(--semantic-font-family-base, /* ⚠️ TOKEN_MANQUANT: semantic.font.family.base */ sans-serif);
  font-size:   var(--semantic-font-size-sm, 0.75rem);
  font-weight: var(--semantic-font-weight-medium, 500);
  line-height: var(--semantic-line-height-tight, 1.25);
  color:       var(--component-input-text-default);
  cursor: default;
  user-select: none;
}

.input-field__label--required::after {
  content: " *";
  color: var(--component-input-border-error);
}


.input-field__control {
  position: relative;
  display:  flex;
  flex-direction: row;
  align-items: stretch;
  width: 100%;
}


.input-field__icon {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  display: flex;
  align-items: center;
  pointer-events: none;
  color: var(--component-input-text-placeholder);
  /* default icon size aligned with MD */
  width:  var(--semantic-spacing-md, 16px);
  height: var(--semantic-spacing-md, 16px);
}

.input-field__icon--leading {
  left: var(--component-input-size-md-padding-x);
}

.input-field__icon--trailing {
  right: var(--component-input-size-md-padding-x);
  pointer-events: auto; /* allow click (e.g. clear / password toggle) */
}


.input-field__input {
  /* Layout */
  display:    block;
  width:      100%;
  box-sizing: border-box;

  /* Default size (MD) — overridden via size modifiers */
  min-height:     var(--component-input-size-md-min-height);
  padding-inline: var(--component-input-size-md-padding-x);
  padding-block:  var(--component-input-size-md-padding-y);
  font-size:      var(--component-input-size-md-font-size);

  /* Typography */
  font-family: var(--semantic-font-family-base, sans-serif);
  font-weight: var(--semantic-font-weight-regular, 400);
  line-height: var(--semantic-line-height-normal, 1.5);
  color:       var(--component-input-text-default);

  /* Appearance */
  background-color: var(--component-input-bg-default);
  border:           var(--component-input-border-width) solid var(--component-input-border-default);
  border-radius:    var(--component-input-radius);
  outline:          none;
  appearance:       none;
  -webkit-appearance: none;

  /* Transition */
  transition: var(--component-input-transition);
}

/* Placeholder */
.input-field__input::placeholder {
  color:   var(--component-input-text-placeholder);
  opacity: 1; /* Firefox fix */
}

/* ── HOVER ─────────────────────────────────────────────────── */
.input-field__input:hover:not(:disabled):not(:focus):not([aria-invalid="true"]) {
  border-color: var(--component-input-border-hover);
}

/* ── FOCUS ─────────────────────────────────────────────────── */
.input-field__input:focus:not(:disabled) {
  border-color: var(--component-input-border-focus);
  box-shadow:   0 0 0 var(--component-input-focus-ring-width)
                color-mix(in srgb, var(--component-input-focus-ring-color) 25%, transparent);
}

/* :focus-visible (keyboard nav) — explicit ring on top */
.input-field__input:focus-visible:not(:disabled) {
  outline:        var(--component-input-focus-ring-width) solid var(--component-input-focus-ring-color);
  outline-offset: var(--component-input-focus-ring-offset);
}

/* ── DISABLED ───────────────────────────────────────────────── */
.input-field__input:disabled {
  background-color: var(--component-input-bg-disabled);
  border-color:     var(--component-input-border-disabled);
  color:            var(--component-input-text-disabled);
  cursor:           not-allowed;
  opacity:          1; /* Full opacity; color tokens handle visual muting */
}

.input-field__input:disabled::placeholder {
  color: var(--component-input-text-disabled);
}

/* ── ERROR ──────────────────────────────────────────────────── */
.input-field__input[aria-invalid="true"] {
  border-color: var(--component-input-border-error);
}

.input-field__input[aria-invalid="true"]:focus:not(:disabled) {
  box-shadow: 0 0 0 var(--component-input-focus-ring-width)
              color-mix(in srgb, var(--component-input-border-error) 25%, transparent);
}



/* SM */
.input-field__input--sm {
  min-height:     var(--component-input-size-sm-min-height);
  padding-inline: var(--component-input-size-sm-padding-x);
  padding-block:  var(--component-input-size-sm-padding-y);
  font-size:      var(--component-input-size-sm-font-size);
}

/* MD (already the base — kept explicit for completeness) */
.input-field__input--md {
  min-height:     var(--component-input-size-md-min-height);
  padding-inline: var(--component-input-size-md-padding-x);
  padding-block:  var(--component-input-size-md-padding-y);
  font-size:      var(--component-input-size-md-font-size);
}

/* LG */
.input-field__input--lg {
  min-height:     var(--component-input-size-lg-min-height);
  padding-inline: var(--component-input-size-lg-padding-x);
  padding-block:  var(--component-input-size-lg-padding-y);
  font-size:      var(--component-input-size-lg-font-size);
}


.input-field__input--has-leading-icon {
  padding-inline-start: calc(
    var(--component-input-size-md-padding-x) +     /* icon zone */
    var(--semantic-spacing-md, 16px)          +    /* icon width */
    var(--semantic-spacing-xs, 4px)                /* gap */
  );
}

.input-field__input--sm.input-field__input--has-leading-icon {
  padding-inline-start: calc(
    var(--component-input-size-sm-padding-x) +
    var(--semantic-spacing-md, 16px) +
    var(--semantic-spacing-xs, 4px)
  );
}

.input-field__input--lg.input-field__input--has-leading-icon {
  padding-inline-start: calc(
    var(--component-input-size-lg-padding-x) +
    var(--semantic-spacing-md, 16px) +
    var(--semantic-spacing-xs, 4px)
  );
}

.input-field__input--has-trailing-icon {
  padding-inline-end: calc(
    var(--component-input-size-md-padding-x) +
    var(--semantic-spacing-md, 16px) +
    var(--semantic-spacing-xs, 4px)
  );
}

.input-field__input--sm.input-field__input--has-trailing-icon {
  padding-inline-end: calc(
    var(--component-input-size-sm-padding-x) +
    var(--semantic-spacing-md, 16px) +
    var(--semantic-spacing-xs, 4px)
  );
}

.input-field__input--lg.input-field__input--has-trailing-icon {
  padding-inline-end: calc(
    var(--component-input-size-lg-padding-x) +
    var(--semantic-spacing-md, 16px) +
    var(--semantic-spacing-xs, 4px)
  );
}


.input-field__helper {
  font-family: var(--semantic-font-family-base, sans-serif);
  font-size:   var(--semantic-font-size-xs, /* ⚠️ TOKEN_MANQUANT: semantic.font.size.xs — Figma: — */ 0.75rem);
  font-weight: var(--semantic-font-weight-regular, 400);
  line-height: var(--semantic-line-height-tight, 1.25);
  color:       var(--component-input-text-placeholder);
}

.input-field__helper--error {
  color: var(--component-input-border-error);
}`;

// ─── Types ────────────────────────────────────────────────────────────────────

type InputSize = "sm" | "md" | "lg";

interface InputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "size"> {
  /** Field size variant */
  size?: InputSize;
  /** Visible label text */
  label?: string;
  /** Marks the field as required (appends * to label) */
  required?: boolean;
  /** Helper text displayed below the input */
  helperText?: string;
  /** Puts the field in an error state */
  error?: boolean;
  /** Error message (replaces helperText when error=true) */
  errorMessage?: string;
  /** Leading icon element */
  leadingIcon?: React.ReactNode;
  /** Trailing icon element */
  trailingIcon?: React.ReactNode;
  /** Accessible label for icon-only trailing button */
  trailingIconLabel?: string;
  /** Called when the trailing icon is clicked */
  onTrailingIconClick?: React.MouseEventHandler<HTMLButtonElement>;
}

// ─── Component ────────────────────────────────────────────────────────────────

const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      size = "md",
      label,
      required = false,
      helperText,
      error = false,
      errorMessage,
      leadingIcon,
      trailingIcon,
      trailingIconLabel,
      onTrailingIconClick,
      id: providedId,
      disabled,
      className,
      ...rest
    },
    ref
  ) => {
    const autoId = useId();
    const id = providedId ?? `input-${autoId}`;
    const helperId = `${id}-helper`;

    // BEM modifiers on the native <input>
    const inputClasses = [
      "input-field__input",
      `input-field__input--${size}`,
      leadingIcon  ? "input-field__input--has-leading-icon"  : "",
      trailingIcon ? "input-field__input--has-trailing-icon" : "",
      className ?? "",
    ]
      .filter(Boolean)
      .join(" ");

    const showHelper = helperText || (error && errorMessage);

    return (
      <div className="input-field">
        {/* LABEL */}
        {label && (
          <label
            htmlFor={id}
            className={[
              "input-field__label",
              required ? "input-field__label--required" : "",
            ]
              .filter(Boolean)
              .join(" ")}
          >
            {label}
          </label>
        )}

        {/* CONTROL WRAPPER */}
        <div className="input-field__control">
          {/* Leading icon */}
          {leadingIcon && (
            <span
              className="input-field__icon input-field__icon--leading"
              aria-hidden="true"
            >
              {leadingIcon}
            </span>
          )}

          {/* Native input */}
          <input
            ref={ref}
            id={id}
            disabled={disabled}
            required={required}
            aria-invalid={error ? "true" : undefined}
            aria-describedby={showHelper ? helperId : undefined}
            className={inputClasses}
            {...rest}
          />

          {/* Trailing icon — interactive if handler provided */}
          {trailingIcon &&
            (onTrailingIconClick ? (
              <button
                type="button"
                className="input-field__icon input-field__icon--trailing"
                onClick={onTrailingIconClick}
                aria-label={trailingIconLabel ?? "Action"}
                tabIndex={disabled ? -1 : 0}
                disabled={disabled}
              >
                {trailingIcon}
              </button>
            ) : (
              <span
                className="input-field__icon input-field__icon--trailing"
                aria-hidden="true"
              >
                {trailingIcon}
              </span>
            ))}
        </div>

        {/* HELPER / ERROR MESSAGE */}
        {showHelper && (
          <span
            id={helperId}
            className={[
              "input-field__helper",
              error ? "input-field__helper--error" : "",
            ]
              .filter(Boolean)
              .join(" ")}
            role={error ? "alert" : undefined}
          >
            {error && errorMessage ? errorMessage : helperText}
          </span>
        )}
      </div>
    );
  }
);

Input.displayName = "Input";

Input;

// ─── Storybook-style Demo ─────────────────────────────────────────────────────
// Renders the full variant × size × state matrix for visual QA

const SearchIcon = () => (
  <svg
    width="16"
    height="16"
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <circle cx="7" cy="7" r="4.5" stroke="currentColor" strokeWidth="1.5" />
    <path d="M10.5 10.5L13.5 13.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
  </svg>
);

const EyeIcon = () => (
  <svg
    width="16"
    height="16"
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <path
      d="M1 8s2.667-5 7-5 7 5 7 5-2.667 5-7 5-7-5-7-5z"
      stroke="currentColor"
      strokeWidth="1.5"
    />
    <circle cx="8" cy="8" r="1.75" stroke="currentColor" strokeWidth="1.5" />
