  --component-card-padding-md: var(--spacing-lg, /* ⚠️ TOKEN_MANQUANT: spacing.lg */ 24px);
  --component-card-padding-lg: var(--spacing-xl, /* ⚠️ TOKEN_MANQUANT: spacing.xl */ 32px);

  /* Shape */
  --component-card-radius: var(--radius-lg, /* ⚠️ TOKEN_MANQUANT: radius.lg */ 12px);

  /* Surface */
  --component-card-bg: var(--color-bg-primary, /* ⚠️ TOKEN_MANQUANT: color.bg.primary */ #ffffff);

  /* Border */
  --component-card-border-color: var(--color-border-default, /* ⚠️ TOKEN_MANQUANT: color.border.default */ #e2e8f0);
  --component-card-border-width: 1px;

  /* Shadow */
  --component-card-shadow: var(--shadow-100, /* ⚠️ TOKEN_MANQUANT: shadow.100 */ 0 1px 3px 0 rgba(0,0,0,.10), 0 1px 2px -1px rgba(0,0,0,.10));

