import "./card.css";

/* ============================================================
   Types
   ============================================================ */
type CardSize = "sm" | "md" | "lg";
type CardVariant = "default" | "flat" | "ghost" | "interactive";

interface CardProps {
  /** Padding size variant */
  size?: CardSize;
  /** Visual variant */
  variant?: CardVariant;
  /** Disabled state (interactive cards only) */
  disabled?: boolean;
  /** Optional image src for the media zone */
  imageSrc?: string;
  /** Image alt text */
  imageAlt?: string;
  /** Card title */
  title?: React.ReactNode;
  /** Card description / body text */
  description?: React.ReactNode;
  /** Custom body content (overrides description if provided) */
  children?: React.ReactNode;
  /** Footer slot */
  footer?: React.ReactNode;
  /** Badge / overlay slot */
  badge?: React.ReactNode;
  /** Click handler (promotes to interactive) */
  onClick?: React.MouseEventHandler<HTMLElement>;
  /** Accessible label for interactive cards */
  "aria-label"?: string;
  className?: string;
}

/* ============================================================
   Component
   ============================================================ */
const Card = React.forwardRef<HTMLElement, CardProps>(
  (
    {
      size = "md",
      variant = "default",
      disabled = false,
      imageSrc,
      imageAlt = "",
      title,
      description,
      children,
      footer,
      badge,
      onClick,
      className = "",
      ...rest
    },
    ref
  ) => {
    const isInteractive = variant === "interactive" || !!onClick;

    /* Build BEM class string */
    const classes = [
      "card",
      `card--${size}`,
      variant !== "default" ? `card--${variant}` : "",
      isInteractive ? "card--interactive" : "",
      disabled ? "card--disabled" : "",
      className,
    ]
      .filter(Boolean)
      .join(" ");

    /* Inner content */
    const inner = (
      <>
        {/* Media */}
        {imageSrc && (
          <div className="card__media">
            <img src={imageSrc} alt={imageAlt} loading="lazy" />
          </div>
        )}

        {/* Badge overlay */}
        {badge && <div className="card__badge">{badge}</div>}

        {/* Header */}
        {title && (
          <div className="card__header">
            <h3 className="card__title">{title}</h3>
          </div>
        )}

        {/* Body */}
        <div className="card__body">
          {children ?? (
            description && (
              <p className="card__description">{description}</p>
            )
          )}
        </div>

        {/* Footer */}
        {footer && <div className="card__footer">{footer}</div>}
      </>
    );

    /* Render as <button> when interactive for full a11y */
    if (isInteractive) {
      return (
        <button
          ref={ref as React.Ref<HTMLButtonElement>}
          className={classes}
          disabled={disabled}
          aria-disabled={disabled}
          onClick={onClick}
          type="button"
          {...rest}
        >
          {inner}
        </button>
      );
    }

    return (
      <article
        ref={ref as React.Ref<HTMLElement>}
        className={classes}
        aria-disabled={disabled || undefined}
        {...rest}
      >
        {inner}
      </article>
    );
  }
);

Card.displayName = "Card";

/* ============================================================
   Storybook / Démo — matrice complète variants × sizes × states
   ============================================================ */
