.badge--outline.badge--primary {
  border-color: var(--semantic-color-border-primary);
  color:        var(--semantic-color-content-primary);
}

.badge--outline.badge--success {
  border-color: var(--semantic-color-border-success);
  color:        var(--semantic-color-content-success);
}

.badge--outline.badge--warning {
  border-color: var(--semantic-color-border-warning);
  color:        var(--semantic-color-content-warning);
}

.badge--outline.badge--danger {
  border-color: var(--semantic-color-border-danger);
  color:        var(--semantic-color-content-danger);
}

.badge--outline.badge--info {
  border-color: var(--semantic-color-border-info);
  color:        var(--semantic-color-content-info);
}


.badge--solid.badge--primary {
  /* ⚠️ TOKEN_MANQUANT: semantic.color.surface.primary-solid */
  background-color: var(--color-primary-600,  /* FALLBACK */ #2563eb);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}

.badge--solid.badge--success {
  background-color: var(--color-success-600,  /* FALLBACK */ #16a34a);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}

.badge--solid.badge--warning {
  background-color: var(--color-warning-500,  /* FALLBACK */ #eab308);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}

.badge--solid.badge--danger {
  background-color: var(--color-danger-600,   /* FALLBACK */ #dc2626);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}

.badge--solid.badge--info {
  background-color: var(--color-info-600,     /* FALLBACK */ #0284c7);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}

.badge--solid.badge--neutral {
  background-color: var(--color-neutral-700,  /* FALLBACK */ #334155);
  color:            var(--color-neutral-0,    /* FALLBACK */ #ffffff);
}


.badge--sm {
  /* ⚠️ TOKEN_MANQUANT: component.badge.size.sm.padding-x */
  padding-left:  var(--spacing-xs,    /* FALLBACK */ 0.25rem);
  padding-right: var(--spacing-xs,    /* FALLBACK */ 0.25rem);
  /* ⚠️ TOKEN_MANQUANT: component.badge.size.sm.font-size */
  font-size:     var(--font-size-2xs, /* FALLBACK */ 0.625rem);
}

.badge--md {
  /* Default — uses base .badge values */
  padding-left:  var(--component-badge-padding-x);
  padding-right: var(--component-badge-padding-x);
  font-size:     var(--component-badge-font-size);
}

.badge--lg {
  /* ⚠️ TOKEN_MANQUANT: component.badge.size.lg.padding-x */
  padding-left:  var(--spacing-md,  /* FALLBACK */ 0.75rem);
  padding-right: var(--spacing-md,  /* FALLBACK */ 0.75rem);
  /* ⚠️ TOKEN_MANQUANT: component.badge.size.lg.font-size */
  font-size:     var(--font-size-sm,/* FALLBACK */ 0.875rem);
}



/* Dot indicator */
.badge__dot {
  display:       block;
  flex-shrink:   0;
  width:         var(--component-badge-dot-size);
  height:        var(--component-badge-dot-size);
  border-radius: var(--component-badge-radius);
  background-color: currentColor;
}

/* Icon */
.badge__icon {
  display:     flex;
  align-items: center;
  flex-shrink: 0;
  width:       var(--component-badge-icon-size);
  height:      var(--component-badge-icon-size);
}

.badge__icon > svg {
  width:  100%;
  height: 100%;
}

/* Label text */
.badge__label {
  display:     inline-block;
  line-height: inherit;
}


.badge--interactive {
  cursor:     pointer;
  transition: opacity 120ms ease, box-shadow 120ms ease;
}

.badge--interactive:hover:not(:disabled) {
  opacity: 0.85;
}

.badge--interactive:active:not(:disabled) {
  opacity: 0.7;
}

.badge--interactive:focus-visible {
  outline:        2px solid var(--semantic-color-border-emphasis, #2563eb);
  outline-offset: 2px;
}

.badge--interactive:disabled,
.badge--interactive[aria-disabled="true"] {
  opacity:        0.5;
  cursor:         not-allowed;
  pointer-events: none;
}


.badge__dismiss {
  display:          inline-flex;
  align-items:      center;
  justify-content:  center;
  flex-shrink:      0;
  width:            var(--component-badge-icon-size);
  height:           var(--component-badge-icon-size);
  padding:          0;
  border:           none;
  background:       transparent;
  color:            currentColor;
  cursor:           pointer;
  border-radius:    50%;
  opacity:          0.7;
  transition:       opacity 100ms ease;
  font-size:        inherit;
  line-height:      1;
}

.badge__dismiss:hover {
  opacity: 1;
}

.badge__dismiss:focus-visible {
  outline:        2px solid var(--semantic-color-border-emphasis, #2563eb);
  outline-offset: 1px;
}`;

/* ─── Types ─────────────────────────────────────────────── */
type BadgeVariant  = 'neutral' | 'primary' | 'success' | 'warning' | 'danger' | 'info';
type BadgeAppearance = 'subtle' | 'outline' | 'solid';
type BadgeSize     = 'sm' | 'md' | 'lg';

interface BadgeProps {
  /** Text content */
  label?: string;
  /** Color variant */
  variant?: BadgeVariant;
  /** Visual style */
  appearance?: BadgeAppearance;
  /** Size */
  size?: BadgeSize;
  /** Show a leading dot */
  dot?: boolean;
  /** Leading icon node */
  icon?: React.ReactNode;
  /** Make the badge clickable */
  interactive?: boolean;
  /** Show a dismiss (×) button */
  dismissible?: boolean;
  /** Dismiss callback */
  onDismiss?: () => void;
  /** Click callback (interactive only) */
  onClick?: () => void;
  /** Disabled state (interactive only) */
  disabled?: boolean;
  /** Extra class names */
  className?: string;
  /** Children override label */
  children?: React.ReactNode;
}

/* ─── Component ─────────────────────────────────────────── */
const Badge: React.FC<BadgeProps> = ({
  label,
  variant    = 'neutral',
  appearance = 'subtle',
  size       = 'md',
  dot        = false,
  icon,
  interactive = false,
  dismissible = false,
  onDismiss,
  onClick,
  disabled   = false,
  className  = '',
  children,
}) => {
  /* BEM class builder */
  const classes = [
    'badge',
    `badge--${variant}`,
    `badge--${size}`,
    appearance === 'outline' ? 'badge--outline' : '',
    appearance === 'solid'   ? 'badge--solid'   : '',
    interactive              ? 'badge--interactive' : '',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  const content = (
    <>
      {dot  && <span className="badge__dot" aria-hidden="true" />}
      {icon && <span className="badge__icon" aria-hidden="true">{icon}</span>}
      {(children ?? label) && (
        <span className="badge__label">{children ?? label}</span>
      )}
      {dismissible && (
        <button
          type="button"
          className="badge__dismiss"
          aria-label="Remove badge"
          onClick={(e) => {
            e.stopPropagation();
            onDismiss?.();
          }}
          tabIndex={0}
        >
          {/* × icon — inline SVG to avoid external dep */}
          <svg viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
            <path
              d="M12 4L4 12M4 4l8 8"
              stroke="currentColor"
              strokeWidth="1.5"
              strokeLinecap="round"
              strokeLinejoin="round"
            />
          </svg>
        </button>
      )}
    </>
  );

  if (interactive) {
    return (
      <button
        type="button"
        className={classes}
        onClick={onClick}
        disabled={disabled}
        aria-disabled={disabled}
      >
        {content}
      </button>
    );
  }

  return (
    <span className={classes}>
      {content}
    </span>
  );
};

/* ─── Icon sample (inline) ───────────────────────────────── */
const StarIcon = () => (
  <svg viewBox="0 0 16 16" fill="currentColor" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <path d="M8 1l1.85 3.75 4.15.6-3 2.93.71 4.14L8 10.25l-3.72 1.17.71-4.14-3-2.93 4.15-.6L8 1z" />
  </svg>
);

/* ─── Demo / Storybook render ────────────────────────────── */
const BadgeDemo: React.FC = () => {
  const variants:    BadgeVariant[]    = ['neutral', 'primary', 'success', 'warning', 'danger', 'info'];
  const appearances: BadgeAppearance[] = ['subtle', 'outline', 'solid'];
  const sizes:       BadgeSize[]       = ['sm', 'md', 'lg'];

  const sectionStyle: React.CSSProperties = {
    display:       'flex',
    flexDirection: 'column',
    gap:           '24px',
    fontFamily:    'system-ui, sans-serif',
    padding:       '32px',
    background:    '#f8fafc',
    minHeight:     '100vh',
  };

  const rowStyle: React.CSSProperties = {
    display:    'flex',
    flexWrap:   'wrap',
    gap:        '12px',
    alignItems: 'center',
  };

  const headingStyle: React.CSSProperties = {
    fontSize:     '11px',
    fontWeight:   600,
    textTransform: 'uppercase',
    letterSpacing: '0.08em',
    color:        '#64748b',
    marginBottom: '4px',
  };

  const groupStyle: React.CSSProperties = {
    display:       'flex',
    flexDirection: 'column',
    gap:           '12px',
    background:    '#ffffff',
    borderRadius:  '12px',
    padding:       '20px 24px',
    boxShadow:     '0 1px 3px rgba(0,0,0,.08)',
  };

  return (
    <div style={sectionStyle}>

      {/* ── Variants × Appearances ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Variants × Appearances</p>
        {appearances.map((app) => (
          <div key={app} style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            <p style={{ ...headingStyle, opacity: 0.6, marginBottom: 0 }}>{app}</p>
            <div style={rowStyle}>
              {variants.map((v) => (
                <Badge key={v} variant={v} appearance={app} label={v} />
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* ── Sizes ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Sizes (primary / subtle)</p>
        <div style={rowStyle}>
          {sizes.map((s) => (
            <Badge key={s} variant="primary" size={s} label={`size-${s}`} />
          ))}
        </div>
      </div>

      {/* ── With dot ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>With leading dot</p>
        <div style={rowStyle}>
          {variants.map((v) => (
            <Badge key={v} variant={v} dot label={v} />
          ))}
        </div>
      </div>

      {/* ── With icon ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>With leading icon</p>
        <div style={rowStyle}>
          {variants.map((v) => (
            <Badge key={v} variant={v} appearance="subtle" icon={<StarIcon />} label={v} />
          ))}
        </div>
      </div>

      {/* ── Dismissible ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Dismissible</p>
        <div style={rowStyle}>
          {variants.map((v) => (
            <Badge
              key={v}
              variant={v}
              dismissible
              label={v}
              onDismiss={() => alert(`Dismissed: ${v}`)}
            />
          ))}
        </div>
      </div>

      {/* ── Interactive ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Interactive (button)</p>
        <div style={rowStyle}>
          {variants.map((v) => (
            <Badge
              key={v}
              variant={v}
              interactive
              label={v}
              onClick={() => alert(`Clicked: ${v}`)}
            />
          ))}
        </div>
        <div style={rowStyle}>
          <p style={{ ...headingStyle, margin: 0 }}>Disabled →&nbsp;</p>
          <Badge variant="primary" interactive disabled label="disabled" />
        </div>
      </div>

      {/* ── Dot only (counter-style) ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Dot-only (no label)</p>
        <div style={rowStyle}>
          {variants.map((v) => (
            <Badge key={v} variant={v} dot aria-label={`${v} status`} />
          ))}
        </div>
      </div>

      {/* ── Full matrix: size × appearance × variant ── */}
      <div style={groupStyle}>
        <p style={headingStyle}>Full matrix — size × appearance</p>
        {sizes.map((s) =>
          appearances.map((app) => (
            <div key={`${s}-${app}`} style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              <p style={{ ...headingStyle, opacity: 0.5, marginBottom: 0 }}>
                {s} / {app}
              </p>
              <div style={rowStyle}>
                {variants.map((v) => (
                  <Badge key={v} variant={v} size={s} appearance={app} label={v} />
                ))}
              </div>
            </div>
          ))
        )}
      </div>

    </div>
  );
};

BadgeDemo;

render(<><style>{__css}</style><Badge /></>);
```

fontFamily.description:
## Description développeur
Composant généré par le pipeline IA avec fidélité pixel-perfect Figma. À compléter par le développeur.

## Token Mapping (Figma → CSS)
| Propriété CSS | Token | Figma (valeur exacte) | État |
|---|---|---|---|
| font-family | `--typography-heading-h1-font-family` → résout via `{font.family.default}` | `{font.family.default}` (alias) | default |

## Do & Don't
✅ **Do**
- Utiliser les CSS custom properties (var(--component-*))
- Respecter les états interactifs (hover, active, focus, disabled)
- Vérifier la fidélité visuelle avec la maquette Figma

❌ **Don't**
- Ne pas utiliser de valeurs brutes (px, #hex) — utiliser les tokens
- Ne pas supprimer les états d'accessibilité (:focus-visible)
- Ne pas modifier les dimensions sans vérifier la spec Figma

## 💻 Code interactif (Live Editor)

```jsx
const __css = `/*
 * ============================================================
 * TOKEN : typography.heading.h1.fontFamily
 * Valeur : {font.family.default}  →  var(--font-family-default)
 * ============================================================
 *
 * Hiérarchie de résolution :
 *   Component  : --typography-heading-h1-font-family
 *   Semantic   : --font-family-default          (alias source)
 *   Core       : ⚠️ TOKEN_MANQUANT (voir liste)
 * ============================================================
 */

/* ── Définition du token component ────────────────────────── */
:root {
  /* ⚠️ TOKEN_MANQUANT: font.family.default — Figma alias: {font.family.default}
     La valeur concrète (ex. "Inter", "Roboto"…) n'est pas fournie dans
     les tokens disponibles. Remplacer FALLBACK par la valeur réelle. */
  --font-family-default: /* FALLBACK */ sans-serif;

  --typography-heading-h1-font-family: var(
    --font-family-default,
    /* FALLBACK */ sans-serif
  );
}

/* ── Composant ─────────────────────────────────────────────── */
.heading {
  font-family: var(--typography-heading-h1-font-family);
}

.heading--h1 {
  font-family: var(--typography-heading-h1-font-family);
}`;

import "./heading.css";

/**
 * Heading — token typography.heading.h1.fontFamily
 *
 * Démo de la résolution du token :
 *   typography.heading.h1.fontFamily
 *     → {font.family.default}
 *     → var(--typography-heading-h1-font-family)
 *     → var(--font-family-default)
 *     → [valeur concrète manquante — voir tokens_manquants]
 */

type HeadingLevel = "h1" | "h2" | "h3" | "h4" | "h5" | "h6";

interface HeadingProps {
  level?: HeadingLevel;
  children?: React.ReactNode;
  className?: string;
}

const Heading: React.FC<HeadingProps> = ({
  level = "h1",
  children = "The quick brown fox jumps over the lazy dog",
  className = "",
}) => {
  const Tag = level as keyof JSX.IntrinsicElements;
  return (
    <Tag className={`heading heading--${level} ${className}`.trim()}>
      {children}
    </Tag>
  );
};

/* ── Storybook / démo render ─────────────────────────────── */
const HeadingDemo: React.FC = () => (
  <div
    style={{
      display: "flex",
      flexDirection: "column",
      gap: "1.5rem",
      padding: "2rem",
      background: "#fff",
    }}
  >
    {/* ── Token resolution trace ── */}
    <section
      style={{
        background: "#f5f5f5",
        borderRadius: "6px",
        padding: "1rem 1.25rem",
        fontFamily: "monospace",
        fontSize: "0.8rem",
        lineHeight: "1.7",
      }}
    >
      <strong>Token resolution</strong>
      <br />
      <code>typography.heading.h1.fontFamily</code>
      <br />
      &nbsp;&nbsp;→ <code>&#123;font.family.default&#125;</code>
      <br />
      &nbsp;&nbsp;→ <code>var(--typography-heading-h1-font-family)</code>
      <br />
      &nbsp;&nbsp;→ <code>var(--font-family-default)</code>
      <br />
      &nbsp;&nbsp;→{" "}
      <span style={{ color: "#c0392b" }}>
        ⚠️ TOKEN_MANQUANT — valeur concrète non fournie
      </span>
    </section>

    {/* ── Matrice des niveaux de titre ── */}
    <section>
      <p
        style={{
          margin: "0 0 0.75rem",
          fontSize: "0.75rem",
          fontFamily: "monospace",
          color: "#666",
        }}
      >
        Matrice — tous niveaux × token appliqué
      </p>

      {(["h1", "h2", "h3", "h4", "h5", "h6"] as HeadingLevel[]).map(
        (level) => (
          <div
            key={level}
            style={{
              display: "flex",
              alignItems: "baseline",
              gap: "1rem",
              borderBottom: "1px solid #eee",
              paddingBottom: "0.5rem",
              marginBottom: "0.5rem",
            }}
          >
            <span
              style={{
                fontFamily: "monospace",
                fontSize: "0.7rem",
                color: "#999",
                minWidth: "2rem",
              }}
            >
              {level}
            </span>
            <Heading level={level}>
              Titre niveau {level.toUpperCase()} — font-family token
            </Heading>
          </div>
        )
      )}
    </section>

    {/* ── Computed value inspector ── */}
    <section
      style={{
        background: "#fffbea",
        border: "1px solid #f0c040",
