        fontSize: "0.8rem",
        fontFamily: "monospace",
      }}
    >
      <strong>⚠️ Token manquant détecté</strong>
      <br />
      <code>--font-family-default</code> n'est pas résolu dans les tokens
      fournis.
      <br />
      Fallback actif : <code>sans-serif</code>
    </section>
  </div>
);

HeadingDemo;

render(<><style>{__css}</style><Heading /></>);
